lexer grammar SYsULexer;

// Keywords
Void : 'void';
Int : 'int';
Return : 'return';
If : 'if';
Else : 'else';
While : 'while';
Break : 'break';
Continue : 'continue';

// Operators - multi-char first
AmpAmp : '&&';
PipePipe : '||';
EqualEqual : '==';
NotEqual : '!=';
LessEqual : '<=';
GreaterEqual : '>=';
Less : '<';
Greater : '>';

// Single char operators
Plus : '+';
Minus : '-';
Star : '*';
Slash : '/';
Percent : '%';
Equal : '=';
Exclaim : '!';
Amp : '&';
Pipe : '|';

// Punctuation
LeftParen : '(';
RightParen : ')';
LeftBracket : '[';
RightBracket : ']';
LeftBrace : '{';
RightBrace : '}';

Semi : ';';
Comma : ',';

// Identifier
Identifier
    :   IdentifierNondigit
        (   IdentifierNondigit
        |   Digit
        )*
    ;

fragment
IdentifierNondigit
    :   Nondigit
    ;

fragment
Nondigit
    :   [a-zA-Z_]
    ;

fragment
Digit
    :   [0-9]
    ;

// Constants
Constant
    :   IntegerConstant
    ;

fragment
IntegerConstant
    :   DecimalConstant
    |   OctalConstant
    |   HexadecimalConstant
    ;

fragment
DecimalConstant
    :   NonzeroDigit Digit*
    ;

fragment
OctalConstant
    :   '0' OctalDigit*
    ;

fragment
HexadecimalConstant
    :   HexadecimalPrefix HexadecimalDigit+
    ;

fragment
HexadecimalPrefix
    :   '0' [xX]
    ;

fragment
HexadecimalDigit
    :   [0-9a-fA-F]
    ;

fragment
NonzeroDigit
    :   [1-9]
    ;

fragment
OctalDigit
    :   [0-7]
    ;


// Line directives for preprocessor info
LineDirective
    :   '#' Whitespace* ~[\r\n]*
        -> skip
    ;

// Whitespace
Whitespace
    :   [ \t]+
        -> skip
    ;

// Newline
Newline
    :   (   '\r' '\n'?
        |   '\n'
        )
        -> skip
    ;

